-- Poems batch 63
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8b6815df-fa6d-4a4e-951e-b1edb4ed265e','登第後自詠（題擬）','崔玄亮','唐','唐诗','tang','','[]','人間不會雲間事，應笑蓬萊最後仙。',93,'全唐诗/poet.tang.53000.json','["人間不會雲間事，應笑蓬萊最後仙。", "（見前書卷二三《得湖州崔十八使君書喜與杭越鄰郡因成長句代賀兼寄微之》詩末自注引）（按：白氏詩注云：「貞元初同登科，崔君名最在後。", "當時崔自詠云〖略〗。", "」）。"]'),
('08e4f7d6-5987-4d64-9f5c-8d1ba22c8c0d','石牀石鑑','李郃','唐','唐诗','tang','','[]','麓牀高接天，伏虎上棲煙。',152,'全唐诗/poet.tang.53000.json','["麓牀高接天，伏虎上棲煙。", "松低輕蓋偃，藤細若鉤懸。", "石明如掛鏡，照物別媸妍。", "鶴鸞時弄影，何處覓神仙。", "（見嘉慶十一年曾珏纂《寧遠縣志》卷九）（按：《沅湘耆舊集》卷三以此詩爲二首，前四句題作《麓牀》，後四句題作《石鑑》。", "今詳詩意，似作一首爲是。", "又此詩與《全唐詩》卷七七駱賓王《出石門》甚相似，疑即據駱詩僞託。", "）。"]'),
('d8262d60-5203-483f-b615-0c26acd3c5f6','贈杜顗','崔岐','唐','唐诗','tang','','[]','賈馬死來生杜顗，中間寥落一千年。',51,'全唐诗/poet.tang.53000.json','["賈馬死來生杜顗，中間寥落一千年。", "（見《樊川文集》卷九《唐故淮南支使試大理評事兼監察御史杜君墓誌銘》）。"]'),
('ce03e565-1cc7-44c5-8074-77b0d9cb4c5d','和入京','呂讓','唐','唐诗','tang','','[]','俘囚經萬里，憔悴度三春。',145,'全唐诗/poet.tang.53000.json','["俘囚經萬里，憔悴度三春。", "髮改河陽鬢，衣餘京洛塵。", "鍾儀悲去楚，隨會泣留秦。", "既謝（一作「得」）平吳利，終成失路人。", "（見《文苑英華》卷二四○）（按：《古詩紀》、《全隋詩》及逯欽立輯《先秦漢魏晉南北朝詩》皆收此詩爲隋詩，實誤。", "隋無呂讓其人，《文苑英華》另收呂讓大和八年作《楚州刺史廳記》，可證。", "）。"]'),
('ec536673-1b03-449f-8251-0955d88707d7','','范酇','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('bd29a438-27c7-4f90-bc06-f927356dffba','句','范酇','唐','唐诗','tang','','[]','歲盡天涯雨。',40,'全唐诗/poet.tang.53000.json','["歲盡天涯雨。", "（見《唐詩紀事》卷五十、《增修詩話總龜前集》卷十四引《北夢瑣言》）。"]'),
('97761d17-a4a7-43c5-9b04-658391a8bb6a','與于駙馬','嚴休復','唐','唐诗','tang','','[]','莫惜歌喉一串珠。',38,'全唐诗/poet.tang.53000.json','["莫惜歌喉一串珠。", "（見《白氏長慶集》卷三二《寄明州于駙馬使君三絕句》自注引）。"]'),
('4ff971ec-a73b-4b6c-b611-613c698a6906','句','盧仝','唐','唐诗','tang','','[]','不鯽溜鈍漢。',20,'全唐诗/poet.tang.53000.json','["不鯽溜鈍漢。", "（見《宋景文公筆記》卷上）。"]'),
('6b84e887-d366-402f-9d85-575c16bca6a5','','陸亘','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('1ff534e5-11f4-479c-a543-fa6f27a95434','遊天衣寺','陸亘','唐','唐诗','tang','','[]','處世空旦夕，探幽放情志。',134,'全唐诗/poet.tang.53000.json','["處世空旦夕，探幽放情志。", "長歌向閑雲，引客遊古寺。", "秦山倚寥廓，高鳥下蒼翠。", "凝陰向杉松，界法齊天地。", "疏鐘遠僧舍，深殿有猨戲。", "警梵千谿中，真禪寂無二。", "寒泉聳毛髮，清露遣心累。", "省慮因悟非，勞神豈爲貴。", "起然靜中見，覺了愚勝智。", "願得棲煙霞，書之謝名利。", "（見《會稽掇英總集》卷八）。"]'),
('2b262ce7-9213-46d6-aff6-2433d868402f','白雲亭','沈傳師','唐','唐诗','tang','','[]','僧愛白雲溪上飛，白雲深處敞禪扉。',54,'全唐诗/poet.tang.53000.json','["僧愛白雲溪上飛，白雲深處敞禪扉。", "莫言便是無情物，思着故鄉依舊歸。", "（見嘉慶二十年洪亮吉纂《寧國府志》卷二四）。"]'),
('ee521572-29c6-4d86-8d39-2e7a6195e89e','讚碎金','沈傳師','唐','唐诗','tang','','[]','墨寶三千三百餘，展開勝讀兩車書。',50,'全唐诗/poet.tang.53000.json','["墨寶三千三百餘，展開勝讀兩車書。", "人間要字應來盡，呼作零金也不虛。", "（見斯六二○四卷，原署「沈侍郎」）。"]'),
('5dbbffa9-4700-4682-8ff4-6b314189c0f8','久住投機偈','普願','唐','唐诗','tang','','[]','今日還鄉入大門，南泉親道遍乾坤。',45,'全唐诗/poet.tang.53000.json','["今日還鄉入大門，南泉親道遍乾坤。", "法法分明皆祖父，迴頭慚愧好兒孫。", "（見《景德傳燈錄》卷十）。"]'),
('49975b99-5688-4ed1-bfa1-5e33988154a4','偈','性空','唐','唐诗','tang','','[]','烏不前，兔不後，幾人於此茫然走。',43,'全唐诗/poet.tang.53000.json','["烏不前，兔不後，幾人於此茫然走。", "祇有闍黎達本源，結舌何曾着空有？", "（《五燈會元》卷五）。"]'),
('e1a82a93-98ec-45ac-a14f-88bf2adac587','宮詞','王涯','唐','唐诗','tang','','[]','簾外微明燭下粧，殿明放鎖待君王。',52,'全唐诗/poet.tang.53000.json','["簾外微明燭下粧，殿明放鎖待君王。", "玉階地冷羅鞋薄，衆裏偷身倚玉牀。", "（《分門纂類唐宋時賢千家詩選》卷十六）。"]'),
('e47793f4-f3e8-499d-ab55-38516a9d5071','','崔覲','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('19e033de-2111-4f36-910a-d3c1833d84b6','灙谷','崔覲','唐','唐诗','tang','','[]','高峰偃蹇雲崔嵬，層崖巨壑長峽開。',79,'全唐诗/poet.tang.53000.json','["高峰偃蹇雲崔嵬，層崖巨壑長峽開。", "龍蛇縱橫虎豹亂，古（《洋縣志》作「石」）棧朽滅埋深苔。", "（見宋祝穆《方輿勝覽》卷六六，校以光緒二十八年張鵬翼纂《洋縣志》卷七）。"]'),
('7bdbab1e-2a3e-4af2-8773-9f822e849a5e','缺題','崔覲','唐','唐诗','tang','','[]','寥寥官舍靜於僧，雖有園亭亦倦登。',32,'全唐诗/poet.tang.53000.json','["寥寥官舍靜於僧，雖有園亭亦倦登。", "桃李光陰流似水，圖書滋味冷如冰。"]'),
('3cf5f554-c04e-4d6c-a4de-41e01f390480','缺題','崔覲','唐','唐诗','tang','','[]','地形連楚濶，山勢入秦豪。',36,'全唐诗/poet.tang.53000.json','["地形連楚濶，山勢入秦豪。", "平外斜通駱，深中遠認褒。", "圖經何壯觀，故事有蕭曹。"]'),
('d38180fe-43a5-4565-9b95-ace473f8be4a','漢中城樓','崔覲','唐','唐诗','tang','','[]','斷煙橫沔水，孤鶩入洋州。',25,'全唐诗/poet.tang.53000.json','["斷煙橫沔水，孤鶩入洋州。", "（按：四句當分屬二首。", "）。"]'),
('6cdc17a4-37b6-4619-92b5-648242b04077','廉水渡','崔覲','唐','唐诗','tang','','[]','江水不流廉節去，清名長解勝貪泉。',16,'全唐诗/poet.tang.53000.json','["江水不流廉節去，清名長解勝貪泉。"]'),
('f441d47e-7e61-454b-9dc4-b5dab22e035a','教場','崔覲','唐','唐诗','tang','','[]','豈知王子山前月，曾照曹劉夜戰來。',16,'全唐诗/poet.tang.53000.json','["豈知王子山前月，曾照曹劉夜戰來。"]'),
('f6d890d1-b1a8-40f2-b30d-36f9c00bf3b2','句','崔覲','唐','唐诗','tang','','[]','直望漢江三百里，一條如線下洋州。',363,'全唐诗/poet.tang.53000.json','["直望漢江三百里，一條如線下洋州。", "（以上六題均見宋王象之《輿地紀勝》卷一八三《興元府》）（〖1〗北宋文同《丹淵集》卷十五《崔覲詩》〖原注：大中時人〗：「崔覲者高士，梁州城固人。", "讀書不求官，但與耕稼親。", "夫婦既已老，左右無子孫。", "一日召奴婢，盡以田宅均。", "俾之各爲業，不用來相聞。", "遂去隱南山，雜跡麋鹿羣。", "約曰或過汝，所給爲我陳。", "有時携其妻，來至諸人門。", "乃與具酒食，嘯詠相歡欣。", "山南鄭餘慶，辟之爲參軍。", "見趣使就職，漫不知吏文。", "已復許謝事，但謂長者云。", "補闕王直方，本覲之比鄰。", "文宗時上書，召見蒙咨詢。", "薦覲有高行，用可追至淳。", "詔授起居郎，裒斜走蒲輪。", "辭疾不肯至，高風概秋旻。", "我昨過其縣，裴回想芳塵。", "訪問諸故老，寂無祠與墳。", "斯人久不競，薄夫何由敦？", "此縣漢唐時，諸公揚清芬。", "刻詩子堅廟，來者期不泯。", "」按：文同於北宋熙寧六年知漢中府，此詩爲其時作。"]'),
('8d175677-7022-45fd-904f-11db7e4d1193','過金山寺','空海','唐','唐诗','tang','','[]','古貌滿堂塵暗色，新華落地鳥繁聲。',61,'全唐诗/poet.tang.53000.json','["古貌滿堂塵暗色，新華落地鳥繁聲。", "經行觀禮自心感，一雨僧人不顯名。", "（《經國集》卷十。", "轉錄自《空海全集》第七卷《拾遺雜集》）。"]'),
('7cece203-8db8-49ea-97f2-74f1f885a3bc','青龍寺留別義操闍梨','空海','唐','唐诗','tang','','[]','同法同門喜遇深，空隨白霧忽歸岑。',37,'全唐诗/poet.tang.53000.json','["同法同門喜遇深，空隨白霧忽歸岑。", "一生一別難再見，非夢思中數數尋。", "（同前）。"]'),
('52ab4868-6bab-45d6-a269-3f7bd452cb1f','在唐日觀昶法和尚小山','空海','唐','唐诗','tang','','[]','看竹看花本國春，人聲鳥哢漢家新。',37,'全唐诗/poet.tang.53000.json','["看竹看花本國春，人聲鳥哢漢家新。", "見君庭際小山色，還識君情不染塵。", "（同前）。"]'),
('812e9615-ef8b-49a1-bcf9-4c1441e30bd9','在唐日贈劍南僧惟上離合詩','空海','唐','唐诗','tang','','[]','磴危人難行，石嶮獸無登。',50,'全唐诗/poet.tang.53000.json','["磴危人難行，石嶮獸無登。", "燭暗迷前後，蜀人不得登。", "（同前）（按：張步雲《唐代逸詩輯存》收入後三首。", "）。"]'),
('a2ccb84f-887e-452d-aba1-a60e8e8400ae','示柳珵（題擬）','鑑空','唐','唐诗','tang','','[]','興一沙衰恒河沙，兔而罝，犬而拏，牛虎相交與角牙，寶檀終不滅其華。',55,'全唐诗/poet.tang.53000.json','["興一沙衰恒河沙，兔而罝，犬而拏，牛虎相交與角牙，寶檀終不滅其華。", "（《宋高僧傳》卷二十《唐洛陽香山寺鑑空傳》）。"]'),
('6aa05c5f-d9d4-48b9-a8ce-3baf9b4cec0a','奉和酬相公賓客漢南留贈八韻','李逢吉','唐','唐诗','tang','','[]','自作分憂別，今方便道過。',237,'全唐诗/poet.tang.53000.json','["自作分憂別，今方便道過。", "悲酸如我少，語笑爲君多。", "淚亦因盃酒，歡非待（一作「侍」）綺羅。", "路[歧]（岐）傷不已，松栢性無他。", "悵望商山老，慇懃漢水波。", "重言塵外約（相公往年垂贈六約），難繼郢中歌。", "玉管離聲發，銀[釭]（缸）曙色和。", "碧霄看又遠，其奈獨愁和。", "（見《文苑英華》卷二四五）（按：《文苑英華》在令狐楚《將赴洛下旅次漢南獻上相公二十兄言懷八韻》後，緊接本詩，署「前人」。", "中華書局影印本新編目錄訂爲李逢吉詩，是。", "二詩押韻相同，詩中事跡亦皆可考，茲不贅述。", "〖《全唐詩》不收此詩〗）。"]'),
('af433fc1-4d0e-495b-ac15-eaaa3de19ab9','句','李逢吉','唐','唐诗','tang','','[]','姮娥歸處月華深。',17,'全唐诗/poet.tang.53000.json','["姮娥歸處月華深。", "（胡偉《宮詞》）。"]'),
('b3737022-e104-4ec9-9a96-985f654a736a','萬卷讚','智常','唐','唐诗','tang','','["\u5e90\u5c71"]','出廓送錢嫌不要，手提葼笠向廬山。',32,'全唐诗/poet.tang.53000.json','["出廓送錢嫌不要，手提葼笠向廬山。", "昔日曾聞青霄鶴，更有青霄鶴不如。"]'),
('09a31558-b2ed-41a7-ba14-4e4e781375f8','偈 一','智常','唐','唐诗','tang','','[]','歸宗事理絕，日輪正當午。',354,'全唐诗/poet.tang.53000.json','["歸宗事理絕，日輪正當午。", "自在如師子，不與物依怙。", "獨步四山頂，優遊三大路。", "吹噓（《燈錄》、《事苑》作「欠呿」）飛禽墮（《燈錄》、《事苑》作「墜」），嚬呻衆獸（《燈錄》、《事苑》作「邪」）怖。", "機豎箭易及，影沒手難覆。", "施張如（《燈錄》、《事苑》作「若」）工（《事苑》作「二」）使，剪截（《燈錄》、《事苑》作「裁剪」）成尺度。", "巧鏤萬盤（《燈錄》、《事苑》作「般」）名，歸宗還似土。", "語密（《燈錄》、《事苑》作「默」）音聲絕，理（《燈錄》作「旨」，《事苑》作「音」）妙言（《燈錄》、《事苑》作「情」）難措。", "棄箇耳（《燈錄》、《事苑》作「眼」）還聾，取箇目還瞽。", "一鏃破三關，分明箭後路。", "𪫧（《燈錄》、《事苑》作「可」）憐箇（《事苑》作「大」）丈夫，先天爲心祖。", "（《祖堂集》卷十五、《景德傳燈錄》卷二九、《祖庭事苑》卷二）。"]'),
('f6ac2144-da7b-45e1-984a-eeb161c4aec2','偈 二','智常','唐','唐诗','tang','','[]','牛皮靸（《五燈會元》作「鞔」）露柱，露柱啾啾叫。',57,'全唐诗/poet.tang.53000.json','["牛皮靸（《五燈會元》作「鞔」）露柱，露柱啾啾叫。", "凡耳聽不聞，諸聖呵呵笑。", "（《景德傳燈錄》卷七、《五燈會元》卷三）。"]'),
('423f0347-c7f1-49aa-b7dc-87e6459d68c5','撥櫂歌 一','德誠','唐','唐诗','tang','','[]','千尺絲綸直下垂，一波纔動萬波隨。',62,'全唐诗/poet.tang.53000.json','["千尺絲綸直下垂，一波纔動萬波隨。", "夜靜水寒魚不食，滿船空載月明歸。", "（按：《五燈會元》卷八載五代時建州白雲令弇禪師引後二句。", "）。"]'),
('4ab29082-f03d-455c-8968-1b9a104c4ff1','撥櫂歌 二','德誠','唐','唐诗','tang','','[]','三十年來（《嘉禾志》作「二十餘年」）江（《五燈會元》作「海」）上遊，水清魚見不吞鉤。',82,'全唐诗/poet.tang.53000.json','["三十年來（《嘉禾志》作「二十餘年」）江（《五燈會元》作「海」）上遊，水清魚見不吞鉤。", "釣竿斫盡重栽竹，不計工夫（《五燈會元》作「功程」，《嘉禾志》作「工程」）得便休。"]'),
('706e9d4e-e77d-40cf-9754-78a541e51691','撥櫂歌 三','德誠','唐','唐诗','tang','','[]','三（《嘉禾志》作「二」）十餘年（《五燈會元》作「年來」、《四溟詩話》作「年前」）坐釣臺，竿（《五燈會元》、《嘉禾志》、《四溟詩話》皆作「鉤」）頭往往得黃龍。',157,'全唐诗/poet.tang.53000.json','["三（《嘉禾志》作「二」）十餘年（《五燈會元》作「年來」、《四溟詩話》作「年前」）坐釣臺，竿（《五燈會元》、《嘉禾志》、《四溟詩話》皆作「鉤」）頭往往得黃龍。", "錦（《五燈會元》、《四溟詩話》作「金」）麟不遇空（《嘉禾志》作「虛」）勞力，收取（《四溟詩話》作「拾」）絲綸歸去來。", "（以上三首，《嘉禾志》題作《自題三絕》）。"]'),
('925c6421-e55d-4c97-82ca-36334f659a7b','撥櫂歌 四','德誠','唐','唐诗','tang','','[]','一葉虛舟一副竿，了然無事坐煙灘。',32,'全唐诗/poet.tang.53000.json','["一葉虛舟一副竿，了然無事坐煙灘。", "忘得喪，任悲歡，却教人喚有多端。"]'),
('276217ef-bebf-48b1-92eb-af4acf5a25fa','撥櫂歌 五','德誠','唐','唐诗','tang','','[]','一任孤舟正又斜，乾坤何路指生涯。',32,'全唐诗/poet.tang.53000.json','["一任孤舟正又斜，乾坤何路指生涯。", "拋歲月，臥煙霞，在處江山便是家。"]'),
('57fc74eb-5dcb-4736-8217-cc2c234a2fff','撥櫂歌 六','德誠','唐','唐诗','tang','','[]','愚人未識主人公，終日孜孜恨不同。',56,'全唐诗/poet.tang.53000.json','["愚人未識主人公，終日孜孜恨不同。", "到彼岸，出樊籠，元來祇是舊時翁。", "（以上三首，《嘉禾志》題作《題松澤西亭三首》）。"]'),
('29bc5fb7-7ebc-4165-b951-fca01cb2f9b7','撥櫂歌 七','德誠','唐','唐诗','tang','','[]','有一魚兮日溯洄（《五燈會元》作「偉莫裁」），混虛（《五燈會元》作「融」）包納信奇哉。',58,'全唐诗/poet.tang.53000.json','["有一魚兮日溯洄（《五燈會元》作「偉莫裁」），混虛（《五燈會元》作「融」）包納信奇哉。", "能變化，吐風雷，下線何曾釣得來。"]'),
('46148f16-9189-4be4-a8f9-0a545f4c8ce1','撥櫂歌 八','德誠','唐','唐诗','tang','','[]','別人祇看採芙蓉，香氣長黏繞指風。',32,'全唐诗/poet.tang.53000.json','["別人祇看採芙蓉，香氣長黏繞指風。", "兩岸映，一船紅，何曾解染得虛空。"]'),
('92d66b66-f289-4310-bcd5-ba0caae3c364','撥櫂歌 九','德誠','唐','唐诗','tang','','[]','問我生涯祇是船，子孫各自賭機緣。',32,'全唐诗/poet.tang.53000.json','["問我生涯祇是船，子孫各自賭機緣。", "不由地，不由天，除却簑衣無可傳。"]'),
('71e0e045-0bbc-435a-a6fd-393483c8a7c3','撥櫂歌 十','德誠','唐','唐诗','tang','','[]','莫學他家弄釣船，海風起也不知邊。',32,'全唐诗/poet.tang.53000.json','["莫學他家弄釣船，海風起也不知邊。", "風拍岸，浪掀天，不易安排得帖然。"]'),
('b5fd3085-0818-4047-bdf5-750b810dd60f','撥櫂歌 十一','德誠','唐','唐诗','tang','','[]','大釣何曾離釣求，拋竿卷線却成愁。',32,'全唐诗/poet.tang.53000.json','["大釣何曾離釣求，拋竿卷線却成愁。", "活潑潑，樂悠悠，自是遲疑不下鉤。"]'),
('d2768564-7be9-4ffb-9cac-e2795e4722aa','撥櫂歌 十二','德誠','唐','唐诗','tang','','[]','靜在須禪動即禪，斷雲孤鶴兩蕭然。',32,'全唐诗/poet.tang.53000.json','["靜在須禪動即禪，斷雲孤鶴兩蕭然。", "煙浦畔，月川前，槁木形骸在一船。"]'),
('8aeb1cb4-eea1-4379-80b9-c46929d0d077','撥櫂歌 十三','德誠','唐','唐诗','tang','','[]','莫道無修便不修，菩提癡坐若爲求？勤作櫂，慧爲舟，者箇男兒始出頭。',32,'全唐诗/poet.tang.53000.json','["莫道無修便不修，菩提癡坐若爲求？勤作櫂，慧爲舟，者箇男兒始出頭。"]'),
('8caf0ace-7f7f-4293-b6c3-949e452559a2','撥櫂歌 十四','德誠','唐','唐诗','tang','','[]','水色山光處處新，本來不俗不同塵。',32,'全唐诗/poet.tang.53000.json','["水色山光處處新，本來不俗不同塵。", "著氣力，用精神，莫作虛生浪死人。"]'),
('c35b55dc-629f-4caa-9bc1-5d5a4454419e','撥櫂歌 十五','德誠','唐','唐诗','tang','','[]','獨倚蘭橈入遠灘，江花漠漠水漫漫。',32,'全唐诗/poet.tang.53000.json','["獨倚蘭橈入遠灘，江花漠漠水漫漫。", "空鉤線，沒腥羶，那得凡魚都上竿。"]'),
('8f0c295b-00d6-47e7-a085-fc626231870a','撥櫂歌 十六','德誠','唐','唐诗','tang','','[]','揭却雲篷進却船，一竿雲影一潭煙。',32,'全唐诗/poet.tang.53000.json','["揭却雲篷進却船，一竿雲影一潭煙。", "既擲網，又拋筌，莫教倒被釣絲牽。"]'),
('63c5b5e6-5279-4b2f-8ffc-f8526992db37','撥櫂歌 十七','德誠','唐','唐诗','tang','','[]','蒼苔滑淨坐忘機，截眼寒雲葉葉飛。',33,'全唐诗/poet.tang.53000.json','["蒼苔滑淨坐忘機，截眼寒雲葉葉飛。", "戴箬笠，掛簑衣，別無歸處是吾歸。", "。"]'),
('30dd5257-fc0a-427e-b9bc-964b16fb6386','撥櫂歌 十八','德誠','唐','唐诗','tang','','[]','外却形骸放却情，蕭然孤坐一舟輕。',32,'全唐诗/poet.tang.53000.json','["外却形骸放却情，蕭然孤坐一舟輕。", "圓月上，四方明，不是奇人不易行。"]'),
('0b179ef1-2e25-4cdb-b250-0e2dfa0a6ead','撥櫂歌 十九','德誠','唐','唐诗','tang','','[]','世知吾懶懶原真，宇宙船中不管身。',32,'全唐诗/poet.tang.53000.json','["世知吾懶懶原真，宇宙船中不管身。", "烈香飲，落花茵，祖師元是箇閑人。"]'),
('8b7984fe-b23a-42d8-99e8-efe5e1efcad9','撥櫂歌 二十','德誠','唐','唐诗','tang','','[]','都大無心罔象間，此中那許是非關。',32,'全唐诗/poet.tang.53000.json','["都大無心罔象間，此中那許是非關。", "山兀兀，水潺潺，忙者自忙閑者閑。"]'),
('05c1f170-b8e3-4548-8919-66ca4669749f','撥櫂歌 二十一','德誠','唐','唐诗','tang','','[]','浪宕從來水郭間，高歌欹枕看遙山。',32,'全唐诗/poet.tang.53000.json','["浪宕從來水郭間，高歌欹枕看遙山。", "紅蓼岸，白蘋灣，肯被蘭橈使不閑。"]'),
('b6738682-e1d7-4b15-80d2-df674689b820','撥櫂歌 二十二','德誠','唐','唐诗','tang','','[]','古釣先生鶴髮垂，穿波出浪不曾疑。',32,'全唐诗/poet.tang.53000.json','["古釣先生鶴髮垂，穿波出浪不曾疑。", "心蕩蕩，笑怡怡，長道無人畫得伊。"]'),
('0fbb636d-87c0-4c2b-b863-dd9bc0e5a935','撥櫂歌 二十三','德誠','唐','唐诗','tang','','[]','動靜由來本兩空，誰教日夜強施功。',32,'全唐诗/poet.tang.53000.json','["動靜由來本兩空，誰教日夜強施功。", "波渺渺，霧濛濛，却來江上隱雲中。"]'),
('c6a01f0b-b358-4b82-9f4e-c2f6a51a4634','撥櫂歌 二十四','德誠','唐','唐诗','tang','','[]','媚俗無機獨任真，何須洗耳復澄神。',32,'全唐诗/poet.tang.53000.json','["媚俗無機獨任真，何須洗耳復澄神。", "雲與月，友兼親，敢向浮漚任此身。"]'),
('4071597f-b09a-486f-87f9-983b216918e4','撥櫂歌 二十五','德誠','唐','唐诗','tang','','[]','逐塊追歡不識休，津梁渾不掛心頭。',32,'全唐诗/poet.tang.53000.json','["逐塊追歡不識休，津梁渾不掛心頭。", "霜葉落，岸花秋，却教漁父爲人愁。"]'),
('1cc3aecd-fba8-4460-98d2-de9fd9c998e5','撥櫂歌 二十六','德誠','唐','唐诗','tang','','[]','一片江雲倏忽開，翳空晴日絕塵埃。',16,'全唐诗/poet.tang.53000.json','["一片江雲倏忽開，翳空晴日絕塵埃。"]'),
('d0c1b941-273d-4377-bc2b-fc2488cb9abf','撥櫂歌 二十七','德誠','唐','唐诗','tang','','[]','鼓櫂高歌自適情，音稀和寡不求名。',32,'全唐诗/poet.tang.53000.json','["鼓櫂高歌自適情，音稀和寡不求名。", "清風起，浪花平，也且隨流逐勢行。"]'),
('9a5550fd-a7c0-4607-a9d5-f5a7bc206e2e','撥櫂歌 二十八','德誠','唐','唐诗','tang','','[]','不妨綸線不妨鉤，祇要鉤輪得自由。',32,'全唐诗/poet.tang.53000.json','["不妨綸線不妨鉤，祇要鉤輪得自由。", "擲即擲，收即收，無蹤無跡樂悠悠。"]'),
('d2c2aa9f-0b15-442b-94e9-d83cb396452e','撥櫂歌 二十九','德誠','唐','唐诗','tang','','[]','鉤下俄逢赤水珠，光明圓徹等清虛。',32,'全唐诗/poet.tang.53000.json','["鉤下俄逢赤水珠，光明圓徹等清虛。", "靜即出，覓還無，不在驪龍不在魚。"]'),
('2b2fbf34-c601-4bd4-b94a-e46374619daa','撥櫂歌 三十','德誠','唐','唐诗','tang','','[]','臥海拏雲勢莫知，優悠何處不相宜。',32,'全唐诗/poet.tang.53000.json','["臥海拏雲勢莫知，優悠何處不相宜。", "香象子，大龍兒，甚麽波濤颺得伊。"]'),
('4f9d4f22-4b65-42a6-8cbf-d74cbd416155','撥櫂歌 三十一','德誠','唐','唐诗','tang','','[]','雖慕求魚不食魚，網帘蓬戶本空無。',32,'全唐诗/poet.tang.53000.json','["雖慕求魚不食魚，網帘蓬戶本空無。", "在世界，作凡夫，知聞祇是箇毘盧。"]'),
('26213571-4b04-47e0-a740-72ddee580ca9','撥櫂歌 三十二','德誠','唐','唐诗','tang','','[]','香餌竿頭也不無，向來祇是釣名魚。',32,'全唐诗/poet.tang.53000.json','["香餌竿頭也不無，向來祇是釣名魚。", "波沃日，浪涵虛，萬象牢籠號有餘。"]'),
('3b83545f-df66-49d9-be19-98c2e15a78ad','撥櫂歌 三十三','德誠','唐','唐诗','tang','','[]','乾坤爲舸月爲篷，一帶雲山一逕風。',33,'全唐诗/poet.tang.53000.json','["乾坤爲舸月爲篷，一帶雲山一逕風。", "身放蕩，性靈空，何妨南北與西東。", "。"]'),
('9173c7a9-169c-45e5-b596-46fbd5c30a78','撥櫂歌 三十四','德誠','唐','唐诗','tang','','[]','終日江頭理櫂間，忽然失濟若爲還。',32,'全唐诗/poet.tang.53000.json','["終日江頭理櫂間，忽然失濟若爲還。", "灘急急，水潺潺，爭把浮生作等閑。"]'),
('9eabd01a-a18c-48cc-8246-a5c17b767849','撥櫂歌 三十五','德誠','唐','唐诗','tang','','[]','有鶴翺翔出海風，往來蹤跡在虛空。',32,'全唐诗/poet.tang.53000.json','["有鶴翺翔出海風，往來蹤跡在虛空。", "圖不得，弄何窮，日月還教沒此中。"]'),
('221c354b-4ee4-44f8-a484-927316c31861','撥櫂歌 三十六','德誠','唐','唐诗','tang','','[]','釣頭曾未曲些些，靜向江濱度歲華。',32,'全唐诗/poet.tang.53000.json','["釣頭曾未曲些些，靜向江濱度歲華。", "酌山茗，折蘆花，誰言埋沒在煙霞。"]'),
('df0f3e50-8db7-4c77-b870-4a82d03904ae','撥櫂歌 三十七','德誠','唐','唐诗','tang','','[]','吾自無心無事間，此心祇有水雲關。',32,'全唐诗/poet.tang.53000.json','["吾自無心無事間，此心祇有水雲關。", "攜釣竹，混塵寰，喧靜都來離又閑。"]'),
('73a07960-f007-4599-9aec-b75b356b0f8f','撥櫂歌 三十八','德誠','唐','唐诗','tang','','[]','晴川清瀨水橫流，瀟灑元同不繫舟。',32,'全唐诗/poet.tang.53000.json','["晴川清瀨水橫流，瀟灑元同不繫舟。", "長自在，任夷猶，將心隨逐幾時休。"]'),
('028858cc-f99f-4dcf-8904-0aeefbed9b63','撥櫂歌 三十九','德誠','唐','唐诗','tang','','[]','歐冶銛鋒價最高，海中收得用吹毛。',470,'全唐诗/poet.tang.53000.json','["歐冶銛鋒價最高，海中收得用吹毛。", "龍鳳繞，鬼神號，不見全牛可下刀。", "（以上三十九首，均見嘉慶間刻本《機緣集》，原爲宋大觀四年風涇海會寺石刻。", "轉錄自《詞學》第二期刊施蟄存先生《船子和尚撥櫂歌》。", "宋明間收錄船子和尚詩偈的著作，筆者所見有：宋釋惠洪《冷齋夜話》卷五、胡仔《苕溪漁隱叢話前集》卷五六收第一首，宋釋慧明《五燈會元》卷五收其一、其二、其三、其七、其八、其九，共六首，宋吳聿《觀林詩話》收第三十九首，元至元《嘉禾志》卷三二收其一至其六，共六首，明謝榛《四溟詩話》卷三收第三首，楊慎《藝林伐山》卷十七收第一至第三首，今即據諸書所引出校。", "）（〖1〗《機緣集》附石刻後呂益柔跋云：「雲間船子和尚嗣法藥山，飄然一舟，泛於華亭吳江洙涇之間。", "夾山一見悟道。", "嘗爲《撥櫂歌》，其傳播人口者纔一二首。", "益柔於先子遺篇中得三十九首，屬詞寄意，脫然迥出塵網之外。", "篇篇可觀，決非庸常學道輩所能亂真者。", "因書以遺風涇海會卿者，俾鑱之石，以資禪客翫味云。", "」〖2〗吳聿《觀林詩話》：「華亭船子和尚詩，少見於世，呂益柔刻三十九首於楓涇寺，云得其父遺編中。", "……涪翁屢用其語。", "」）。"]'),
('29628450-ed70-4f13-88a0-06e4b10c36da','偈','德誠','唐','唐诗','tang','','[]','本是釣魚船上客，偶力須髮著袈裟。',87,'全唐诗/poet.tang.53000.json','["本是釣魚船上客，偶力須髮著袈裟。", "佛祖位中留不住，夜深依舊宿蘆花。", "（見明楊慎《藝林伐山》卷十七《船子和尚四偈》）（〖1〗施蟄存先生云：「此首楊升庵所錄四偈之三，疑是僞作。", "」）。"]'),
('0ab311cf-f1e5-48f4-8efd-babfa1cd2384','王右軍宅','裴通','唐','唐诗','tang','','[]','寂寂金庭洞，清香發桂枝。',118,'全唐诗/poet.tang.53000.json','["寂寂金庭洞，清香發桂枝。", "魚吞左慈釣，鵝踏右軍池。", "此地常無事，冲天自有期。", "向來逢道士，多欲駕文螭。", "（見同治九年刊蔡以瑺撰《鄞縣志》卷二四）（按：宋高似孫《剡錄》卷四及《全唐詩續補遺》卷二十據《永樂大典》卷一三○七四所錄，均僅存前四句。", "）。"]'),
('6d1f11a9-41f7-4838-b932-66086d30e9d9','偈','齊安和尚','唐','唐诗','tang','','[]','猛熾燄中人有路，旋風頂上屹然棲。',55,'全唐诗/poet.tang.53000.json','["猛熾燄中人有路，旋風頂上屹然棲。", "；鎮常歷劫誰差互，杲日無言運照齊。", "（見《景德傳燈錄》卷十、《五燈會元》卷四）。"]'),
('fbc7d9d6-0b1a-49fb-be06-897b8e7b6683','偈','神贊','唐','唐诗','tang','','[]','空門不肯出，投窗也大癡。',36,'全唐诗/poet.tang.53000.json','["空門不肯出，投窗也大癡。", "百年鑽故紙，何日出頭時？", "（見《五燈會元》卷四）。"]'),
('2c7f3369-920e-4bc6-be8a-0be0eeac2638','偈','公畿和尚','唐','唐诗','tang','','[]','有名非大道，是非具不禪。',44,'全唐诗/poet.tang.53000.json','["有名非大道，是非具不禪。", "欲識箇中意，黃葉止啼錢。", "（《祖堂集》卷十七、《五燈會元》卷四）。"]'),
('3c19e1b3-95f4-4563-b8f1-28a6cba77b6f','再勸樂天酒（題擬）','皇甫曙','唐','唐诗','tang','','[]','且勸香醪一屈巵。',37,'全唐诗/poet.tang.53000.json','["且勸香醪一屈巵。", "（《白氏文集管見抄》載白居易《戲酬皇甫十再勸酒》題注引）。"]'),
('6966e2b7-c259-49a9-b288-990f6fc53681','洗墨池','李翺','唐','唐诗','tang','','[]','賸有臨池興，人稱協律郎。',49,'全唐诗/poet.tang.53000.json','["賸有臨池興，人稱協律郎。", "至今蝌蚪跡，猶帶墨痕香。", "（見影印文淵閣《四庫全書》本《湖廣通志》卷八九）。"]'),
('8c1dc282-437f-44f6-b0eb-2a1bcee5d825','惆悵詩','朱慶餘','唐','唐诗','tang','','[]','夢裏分明入漢宮，覺來燈背錦屏空。',99,'全唐诗/poet.tang.53000.json','["夢裏分明入漢宮，覺來燈背錦屏空。", "紫臺日落關山曉，腸斷君恩信畫工。", "（見《才調集》卷八）（按：《才調集》卷七複收此詩於王渙名下，《全唐詩》卷六九○沿之。", "一書而兩見，孰作較難確定，今重收之，以俟知者。", "）。"]'),
('4eafaab6-aaf9-4ee0-b5d8-02dbb996aa92','永嘉百詠 滴水卷','張又新','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('4c9562b6-3b85-47e9-8162-354048dec499','永嘉百詠','張又新','唐','唐诗','tang','','[]','滴水泠泠徹碧紗，旱時無減雨無加。',62,'全唐诗/poet.tang.53000.json','["滴水泠泠徹碧紗，旱時無減雨無加。", "澄清好是爲官侶，引入孤城一帶斜。", "（按：此詩序見明姜準《歧海瑣譚》卷十，承張靖龍同志錄示。", "）。"]'),
('ded43869-73a3-4bb2-8b16-04e72f2fa82b','永嘉百詠 郭公山','張又新','唐','唐诗','tang','','[]','昔賢登步立神州，氣象千年始一浮。',32,'全唐诗/poet.tang.53000.json','["昔賢登步立神州，氣象千年始一浮。", "南望羣州如列宿，北觀江水似龍虬。"]'),
('9e7e1d33-6e07-4bdd-9243-75a12cfe97b2','永嘉百詠 大羅山','張又新','唐','唐诗','tang','','[]','越王曾保此山巔，楊僕樓船幾控弦。',32,'全唐诗/poet.tang.53000.json','["越王曾保此山巔，楊僕樓船幾控弦。", "猶有舊時懸冰在，鮫綃千尺玉潺湲。"]'),
('988c4564-63b4-4748-9b45-ed290d1f7ef1','永嘉百詠 白鶴山','張又新','唐','唐诗','tang','','[]','白鶴山邊秋復春，文君宅畔少風塵。',89,'全唐诗/poet.tang.53000.json','["白鶴山邊秋復春，文君宅畔少風塵。", "欲驅五馬尋真隱，誰是當年入竹人？", "（見永樂《樂清志》卷二、同治丙寅年刊齊召南纂《溫州府志》卷四）（按：《全唐詩》卷四七九收本詩有缺誤，今重錄之。", "）。"]'),
('1a7976de-bed1-4129-994c-c3cae94b2210','永嘉百詠 百里芳','張又新','唐','唐诗','tang','','[]','時清遊騎南徂暑，正值荷花百里開。',50,'全唐诗/poet.tang.53000.json','["時清遊騎南徂暑，正值荷花百里開。", "民喜出行迎五馬，全家知是使君來。", "（光緒《永嘉縣志》卷二一《古跡》）。"]'),
('c4f498ee-6bc3-4350-9806-47595db57427','永嘉百詠 周公廟','張又新','唐','唐诗','tang','','[]','祠像已加唐衮冕，樂工猶服晉衣冠。',65,'全唐诗/poet.tang.53000.json','["祠像已加唐衮冕，樂工猶服晉衣冠。", "（見光緒《永嘉縣志》卷四「橫山周公廟」條）（按：《百里芳》、《周公廟》二題，承張靖龍同志錄示。", "）。"]'),
('55b72585-2509-44c0-8b60-2dd3160ff5fa','永嘉百詠','張又新','唐','唐诗','tang','','[]','空（按：《中界山》詩，《全唐詩》卷四七九已收。',223,'全唐诗/poet.tang.53000.json','["空（按：《中界山》詩，《全唐詩》卷四七九已收。", "按：又新《永嘉百詠》，《全唐詩》卷四七九收《游白鶴山》、《白石巖》〖從一作〗、《羅浮山》、《青嶂山》、《中界山》、《帆游山》、《謝池》、《華蓋山》、《吹臺山》、《青㠗山》、《孤嶼》〖弘治《溫州府志》卷二二題作《改孤嶼爲雙峰》〗、《春草池》等十二首，《全唐詩續補遺》卷八收《題常雲峰》、《太玉洞》〖存二句〗二首，本書補五首，凡存十九首〖二首殘〗。", "從《滴水巷》、《中界山》二詩序推測，各詩原似皆有序。", "）。"]'),
('91674bf8-174e-4a3b-8308-6c161d1ff2d5','臨終（題擬）','鄭居中','唐','唐诗','tang','','[]','雲山遊已徧。',25,'全唐诗/poet.tang.53000.json','["雲山遊已徧。", "（《太平御覽》卷二二二引《唐書》引）。"]'),
('93491d28-3ff1-4c5e-a838-83139f0e80e3','','吳士矩','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('1da4a346-0e85-47b5-aaeb-8a8c279795ed','獨酌謠','吳士矩','唐','唐诗','tang','','[]','愚夫子不招。',52,'全唐诗/poet.tang.53000.json','["愚夫子不招。", "（見《白氏長慶集》卷三三《吳秘監每有美酒獨酌獨醉但蒙詩報不以飲招輒此戲酬兼呈夢得》自注引）。"]'),
('3a96348a-b640-4e26-becb-a7d5fa3cdba3','贈元微之（題擬）','吳士矩','唐','唐诗','tang','','[]','永慚沾藥犬，多謝出囊錐。',44,'全唐诗/poet.tang.53000.json','["永慚沾藥犬，多謝出囊錐。", "（見《元氏長慶集》卷十《開元觀閑居酬吳士矩侍御三十韻》自注引）。"]'),
('1467f885-b7ac-4f2a-bc10-4c82122b9523','句','開成朝士','唐','唐诗','tang','','[]','幾人天上爭仙桂，一歲閩南折四枝。',129,'全唐诗/poet.tang.53000.json','["幾人天上爭仙桂，一歲閩南折四枝。", "（見乾隆十九年刊魯曾煜等纂《福州府志》卷六十《文苑》）（〖1〗《福州府志》：「蕭膺，字次元，侯官人，開成三年登第。", "是歲閩中同舉者三人，朝士詩云〖詩略〗。", "自是閩號爲文儒之鄉。", "官至大理司直。", "」注：「萬曆《府志》，參《閩書》。", "」）。"]'),
('9854fd3c-a18b-49bf-89a7-4c97be13ea6c','九日黃白二菊花盛開對懷劉二十八','令狐楚','唐','唐诗','tang','','[]','西花雖未謝，二菊又初芳。',162,'全唐诗/poet.tang.53000.json','["西花雖未謝，二菊又初芳。", "鬢雲徒云白，腰金未是黃。", "曙花淩露彩，宵豔射星芒。", "日正開邊樹，風清發更香。", "山椒應散亂，籬下倍熒煌。", "泛酒遙相憶，何由共醉狂。", "（見蒲積中《古今歲時雜詠》卷三五）（按：此詩原署「相公」，其次爲劉禹錫和詩「素萼迎寒秀」云云，檢劉詩收《劉賓客外集》卷四，題作《和令狐相公九日對黃白二菊花見懷》，知此詩爲楚作。", "）。"]'),
('80273a21-0d48-4301-aaa9-b37a84b107f9','酬蘇少尹中元夜追懷去年此夕鄙人與故李諫議郭員外見訪感時傷舊之作','令狐楚','唐','唐诗','tang','','[]','直繼先朝衛與英，能移孝友作忠貞。',120,'全唐诗/poet.tang.53000.json','["直繼先朝衛與英，能移孝友作忠貞。", "劍門失險曾縛虎，淮水安流緣斬鯨。", "黃閣碧幢惟是儉，三公二伯未爲榮。", "惠連忽贈池塘句，又遣羸師破膽驚。", "（見蒲積中《古今歲時雜詠》卷二八）（按：《全唐詩》卷四七三收此爲李逢吉詩，題作《奉酬忠武李相公見寄》，疑誤。", "）。"]'),
('38f459a9-fae6-403d-aac8-1b93b38cb926','社日早出赴祠祭','令狐楚','唐','唐诗','tang','','[]','滿城人盡閑，惟我早開關。',32,'全唐诗/poet.tang.53000.json','["滿城人盡閑，惟我早開關。", "慙被家童問，因何別舊山？", "（見同書卷十）。"]'),
('35036542-389e-4071-ac21-62d1d0bdf2c4','鄂州使至竇七副使中丞（《王》作「竇鞏中丞副使」）見示與元（《王》此下有「稹」字）相公獻酬之什鄙人（《王》作「余頃」）任戶部尚書時（《王》作「日」）中丞是當司員外郎每示（《王》作「有」）篇章多相唱和今因（《王》作「因題」）四韻以寄所懷','令狐楚','唐','唐诗','tang','','[]','仙吏秦城別，新詩鄂渚來。',196,'全唐诗/poet.tang.53000.json','["仙吏秦城別，新詩鄂渚來。", "才推今八[斗]（米）（從《王》改），職副舊三台。", "雕鏤心偏許，緘封手自開。", "何年相贈答，却得在中臺。", "（錄自《四部叢刊續編》影宋本《竇氏聯珠集》，以王安石《唐百家詩選》〖簡作《王》〗卷十四所錄詩相校。", "）（按：《全唐詩》卷三三四收此詩，題僅作《和寄竇七中丞》，詩中有誤字，故重錄之。", "同卷同人《秋懷寄錢侍郎》，《唐百寄詩選》作《郢城秋懷寄江州錢徽侍郎》，附記於此，以備徵考。", "）。"]'),
('b0975399-8a14-4f1c-b762-2f6295d0efe1','奉送李相公重鎮襄陽','令狐楚','唐','唐诗','tang','','[]','海內埏埴徧，漢陰旌旆還。',275,'全唐诗/poet.tang.53000.json','["海內埏埴徧，漢陰旌旆還。", "望留丹闕下，恩在紫霄間。", "冰雪背秦嶺，風煙經武關。", "樹皆人尚愛，轅即吏曾攀。", "自惜兩心合，相看雙鬢斑。", "終期謝戎務，同隱鑿龍山。", "（見《文苑英華》卷二四五）（按：《全唐詩》卷四七三收此詩於李逢吉名下，實誤。", "明刻本《文苑英華》誤歸逢吉，中華書局影印本參據各本，重編新目，移歸令狐楚，是。", "檢《唐方鎮年表》卷四，逢吉於元和十五年初任山南東道節度使，至寶曆二年再任，即詩題所謂「重鎮襄陽」。", "《文苑英華》同卷錄逢吉《再赴襄陽辱宣武相公貽詩今用奉酬》，即酬和令狐楚送詩之作，皆六韻。", "《唐方鎮年表》卷二載：楚於長慶四年至大和二年間任宣武軍節度使。", "）。"]'),
('ae393b8b-015b-4e81-8f08-2a02b0c2f57c','重修望京樓因登樓賦詩（題擬）','令狐楚','唐','唐诗','tang','','[]','夷門一鎮五經秋，未得朝天未免愁。',423,'全唐诗/poet.tang.53000.json','["夷門一鎮五經秋，未得朝天未免愁。", "因上此樓望京國，便名樓作望京樓。", "（見宋樂史《太平寰宇記》卷一）（按：《全唐詩》卷五六三收此爲令狐綯詩，題作《登望京樓賦》。", "岑仲勉先生《讀全唐詩札記》云：「按《寰宇記》一開封府浚儀縣，『望京樓，城西門樓，本無名，唐文宗太和二年，節度使令狐綯重修，因登樓賦詩曰』云云，詩中不免作未免。", "據《舊書》一七上，長慶四年九月，『庚戌，以河南尹令狐楚檢校禮部尚書、汴州刺史宣武軍節度宋汴亳觀察等使』，由此計至大和二年，恰是五年。", "綯雖嘗一鎮宣武，但《舊書》一七二《綯傳》云：『咸通二年，改汴州刺史宣武軍節度使，三年冬，遷揚州大都督府長史淮南節度副大使知節度事』，則先後祇兩年，非五經秋也。", "且在大和二年後三十餘祀，紀年亦不合，是知《寰宇記》云令狐綯，實令狐楚之訛，此詩應移收前五函九冊，綯更無他詩，名應刪却。", "」今從其說錄歸楚名下。", "《舊唐書》卷十七上載大和二年十月李逢吉移宣武，「代令狐楚，以楚爲戶部尚書」。", "楚在宣武任時間正與詩合。", "）。"]'),
('5ecac8ff-eae8-48c5-bf76-6da64ee53879','元和初任禮部員外郎作','令狐楚','唐','唐诗','tang','','[]','移石幾回敲廢印，開箱何處送（《吟》作「納」）新圖。',80,'全唐诗/poet.tang.53000.json','["移石幾回敲廢印，開箱何處送（《吟》作「納」）新圖。", "（見《春明退朝錄》卷上。", "《吟窗雜錄》卷四十作初任員外郎作詩。", "）（按：《全唐詩》卷三三四已收二句，故重錄之。", "）。"]'),
('0b110716-b7e4-42af-94b1-2a17b3fbecbc','土圭詩','蕭膺','唐','唐诗','tang','','[]','白日在重雲，如何分曲直。',29,'全唐诗/poet.tang.53000.json','["白日在重雲，如何分曲直。", "（見宋陳應詩《吟窗雜錄》卷二九）。"]'),
('0727ce10-25ca-4646-bc10-54cbe464359b','詠愁','李滂','唐','唐诗','tang','','[]','應緣心裏難停住，化作新絲出鬢邊。',21,'全唐诗/poet.tang.53000.json','["應緣心裏難停住，化作新絲出鬢邊。", "（同前）。"]'),
('60df530e-a6ac-4358-8507-b89aa193e234','','陳嘏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('acacad4c-9447-4e2d-b611-fcb146a235ad','霓裳羽衣曲賦附歌','陳嘏','唐','唐诗','tang','','[]','聖功成兮至樂脩，大道叶兮皇風流。',28,'全唐诗/poet.tang.53000.json','["聖功成兮至樂脩，大道叶兮皇風流。", "（《文苑英華》卷七四）。"]'),
('0d7db4d5-fec9-4f5f-b63c-f34779e185e7','重建東峰亭（有序）','裴丹','唐','唐诗','tang','','[]','大賢志勳略，琢石依崔嵬。',418,'全唐诗/poet.tang.53000.json','["大賢志勳略，琢石依崔嵬。", "聲容問古今，文字埋草萊。", "仰想駐旌戟，仍聞建亭臺。", "胡爲積歲荒，密邇無人開。", "顧鄙作吏間，探幽來此隈。", "披尋忽驚喜，歎咏空徘徊。", "盼睞得殊境，卑高怯冗材。", "薙蕪碧蘚出，芟竹鮮風來。", "危檻架幽谷，飛軒標勝垓。", "分明見城郭，畢竟拋塵埃。", "疊嶂天外展，長溪林際迴。", "平原淡煙境，遠壑生雲雷。", "物象寧極已，英靈信悠哉。", "淒清汎瑤瑟，放浪酣金杯。", "求古外凡意，立言悲自媒。", "永懷紫芝客，眺覽期相陪。", "（清嘉慶十一年刊洪亮吉纂《涇縣志》卷三一）（〖1〗清趙紹祖《涇川金石記》載宋蔣之奇跋云：「裴丹《東峰亭詩》十六句，其碑亡之久矣。", "初中裕得斷碑以示余，有其詩幷序，纔十〖「十」字似爲衍文〗六韻，而闕其十韻。", "今年至水西，及還，中裕以其碑見寄云：『白雲院僧處璡掘土獲之。", "』十六韻皆全，而缺二十餘字。", "其前六韻幷序所缺字，則以斷編正之。", "獨後十韻中缺一字不可考。", "既而公曼復于民間訪得一本爲示，又補後所闕一字，遂爲完篇矣。", "序雖不甚佳，而詩頗近雅，重刻之，所以存故事也。"]'),
('23e27500-7434-42b9-b8c1-c23e409986b4','新開龍泉晉水二池','裴度','唐','唐诗','tang','','[]','方塘含白水。',37,'全唐诗/poet.tang.53000.json','["方塘含白水。", "（見《白氏長慶集》卷三四《又和令公新開龍泉晉水二池詩》注引）。"]'),
('b8a72d65-d651-42cb-87e3-89116f0be76e','夏中雨後遊城南莊示樂天八韻（題擬）','裴度','唐','唐诗','tang','','[]','何處趁盃盤。',41,'全唐诗/poet.tang.53000.json','["何處趁盃盤。", "（見《白氏長慶集》卷三二《奉酬侍中夏中雨後遊城南莊見示八韻》自注引）。"]'),
('4823547a-48da-4931-aa14-4e82a32d629b','送義存出家（題擬）','開成時儒','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('450e923e-427e-4a61-a4bc-16164ec1ca3a','送義存出家（題擬） 一','開成時儒','唐','唐诗','tang','','[]','光陰輪謝又逢春，池柳亭梅幾度新。',32,'全唐诗/poet.tang.53000.json','["光陰輪謝又逢春，池柳亭梅幾度新。", "汝別家鄉須努力，莫將辜負丈夫身。"]'),
('9efb0676-d087-474a-857b-108205496a84','送義存出家（題擬） 二','開成時儒','唐','唐诗','tang','','[]','鹿羣相受豈能成，鸞鳳終須萬里征。',32,'全唐诗/poet.tang.53000.json','["鹿羣相受豈能成，鸞鳳終須萬里征。", "何況故鄉貧與賤，蘇秦花錦事分明。"]'),
('fa4669cf-99b1-44cd-ac54-abb61889d577','送義存出家（題擬） 三','開成時儒','唐','唐诗','tang','','[]','[原憲]（憲原）守貧志不移，顏回安命更誰知？',137,'全唐诗/poet.tang.53000.json','["[原憲]（憲原）守貧志不移，顏回安命更誰知？", "嘉禾未必春前熟，君子從來用有時。", "（見《祖堂集》卷七）（按：《祖堂集》云：「師初出家，時儒假大德送三首詩。", "」師指義存，長慶二年生，十七出家，時在開成三年。", "「假大德」似非人名，「假」疑「賈」之誤，未能臆定，故姑以「開成時儒」立目。", "）。"]'),
('07c0bf3b-39e9-4c17-896d-0487d0699fca','答鹽官齊安國師見招 一','法常','唐','唐诗','tang','','[]','摧殘枯木倚寒（《祖堂集》作「青」）林，幾度逢春不變心。',258,'全唐诗/poet.tang.53000.json','["摧殘枯木倚寒（《祖堂集》作「青」）林，幾度逢春不變心。", "樵客遇（《祖堂集》作「見」）之猶不顧（《比事》作「採」），郢人何事（《祖堂集》作「那更」，《傳燈錄》、《五燈會元》作「那得」）苦追（《比事》作「搜」）尋。", "（見《古今禪藻集》卷七。", "《祖堂集》卷八作曹和尚引古人偈，《景德傳燈錄》卷七、《苕溪漁隱叢話後集》卷三七均作偈，《莆陽比事》卷七引《禪林寶傳》載唐末閩僧躭章稱引此偈，今取以對校。", "）（按：《全唐詩》卷八二三收此詩於躭章名下，誤。", "躭章係引此偈辭鍾傳召，非自作。", "《莆陽比事》云躭章即曹山本寂，可與《祖堂集》相參。", "）。"]'),
('29beb3f1-22be-4c0c-8759-27285d2c5da9','答鹽官齊安國師見招 二','法常','唐','唐诗','tang','','[]','一池荷葉衣無盡，數樹松花食有餘。',231,'全唐诗/poet.tang.53000.json','["一池荷葉衣無盡，數樹松花食有餘。", "剛被世人知住處，又移茆舍（《沅湘耆舊集》作「屋」）入深居。", "（見《五燈會元》卷四、《古今禪藻集》卷七。", "張靖龍云見董慶酉《四明詩幹》卷下引《鄞縣志》、明李鄴嗣《甬上高僧詩》卷首）（按：《沅湘耆舊集》卷十收作隱山和尚詩，似誤。", "《全唐詩》卷八六○收許宣平《見李白詩又吟》，與此詩相似，唯異文較多。", "檢最早記載許宣平詩事沈汾《續仙傳》，幷不載此詩。", "杜文瀾《古謠諺》卷五二引《雲谷臥餘》謂初見于焦竑《焦氏類林》，似候許詩爲明人附會。", "今互收。", "）。"]'),
('ecec7aef-cd12-4e8c-9b49-b1b5796e6a48','偈','宗密','唐','唐诗','tang','','[]','樂兒本是一形軀，乍作官人乍作奴。',44,'全唐诗/poet.tang.53000.json','["樂兒本是一形軀，乍作官人乍作奴。", "名目服章雖改變，始終奴主了無殊。", "（見《宗鏡錄》卷七四）。"]'),
('118c1f50-049a-4ef9-b3fd-eeff63987bb4','座右銘','宗密','唐','唐诗','tang','','[]','寅起可辦事，省語終寡尤。',131,'全唐诗/poet.tang.53000.json','["寅起可辦事，省語終寡尤。", "身安勤戒定，事簡疎交游。", "他非不足辨，己過當自修。", "百歲既有限，世事何時休。", "落髮墮僧數，應須侔上流。", "胡爲逐世變，志慮尚囂浮。", "四恩重山嶽，錙銖未能酧。", "蚩蚩居大廈，汲汲將焉求。", "死生在呼吸，起滅若浮漚。", "無令方服下，番作阿鼻由。", "（《緇門警訓》卷二）。"]'),
('60c84d81-cbc0-428f-bede-a24a5650a635','答復禮禪師《真妄偈》（題擬） 一','宗密','唐','唐诗','tang','','[]','本淨本不覺，由斯妄念起。',61,'全唐诗/poet.tang.53000.json','["本淨本不覺，由斯妄念起。", "知真妄即空，知空妄即止。", "止處名有終，迷時號無始。", "因緣如幻夢，何終復何始？", "此是衆生源，窮之出生死。", "。"]'),
('7976d0c7-6354-4d29-bb70-8cab80baf66a','答復禮禪師《真妄偈》（題擬） 二','宗密','唐','唐诗','tang','','[]','不是真生妄，妄迷真而起。',70,'全唐诗/poet.tang.53000.json','["不是真生妄，妄迷真而起。", "悟妄本自真，知真妄即止。", "妄止似終末，悟來似初始。", "迷悟性皆空，皆空無終始。", "生死由此迷，達此出生死。", "（《林間錄》卷上）。"]'),
('2a58f254-3044-47f8-ac4e-6c320fe7e3f5','望賦附宮人憶月之歌','劉禹錫','唐','唐诗','tang','','[]','張衡側身愁思久，王粲登樓日回首。',44,'全唐诗/poet.tang.53000.json','["張衡側身愁思久，王粲登樓日回首。", "不作渭濱垂釣臣，羞爲洛陽拜塵友。", "（見《劉賓客集》卷一）。"]'),
('4f70a725-9335-4be6-a548-dde8cd86eabe','改高陵人頌劉仁師詩（題擬）','劉禹錫','唐','唐诗','tang','','[]','噫涇水之逶迤，溉我公兮及我私。',214,'全唐诗/poet.tang.53000.json','["噫涇水之逶迤，溉我公兮及我私。", "水無心兮人多僻，錮上游兮乾我澤。", "時逢理兮官得材，墨綬繠兮劉君來。", "能愛人兮恤其隱，心既公兮言既盡。", "縣申府兮府聞天，積憤刷兮沈痾痊。", "劃新渠兮百畝流，行龍蛇兮止膏油。", "遵水式兮復田制，無荒區兮有良歲。", "嗟劉君兮去翺翔，遺我福兮牽我腸。", "紀成功兮鐫美石，求信詞兮昭懿績。", "（見《劉賓客集》卷二《高陵縣令劉君遺愛碑》）（〖1〗碑云：「先是高陵人蒙被惠風而惜於捨去，發于胸懷，播爲聲詩。", "今采其旨而變其詞，志于石。", "」）。"]'),
('6ebc22e3-fb5d-46c4-8552-2ab71205dad7','祭韓吏部文附詩','劉禹錫','唐','唐诗','tang','','[]','岐山威鳳不復鳴，華亭別鶴中夜驚。',61,'全唐诗/poet.tang.53000.json','["岐山威鳳不復鳴，華亭別鶴中夜驚。", "畏簡書兮拘印綬，思臨慟兮志莫就。", "生芻一束酒一杯，故人故人歆此來。", "（見《劉賓客外集》卷十）。"]'),
('6c035f0f-1fa2-4957-ad56-90550fdc724e','聽軋箏','劉禹錫','唐','唐诗','tang','','[]','滿座無言聽軋箏，秋山碧樹一蟬清。',51,'全唐诗/poet.tang.53000.json','["滿座無言聽軋箏，秋山碧樹一蟬清。", "只應曾送秦王女，寫得雲間鸞鳳聲。", "（見《千載佳句》卷下《宴喜門·箏》）。"]'),
('15b098b7-6536-420d-a008-4517bc4739e0','贈樂天','劉禹錫','唐','唐诗','tang','','[]','唯君比萱草，相見可忘憂。',38,'全唐诗/poet.tang.53000.json','["唯君比萱草，相見可忘憂。", "（《白氏長慶集》卷三四《酬夢得比萱草見贈》自注引）。"]'),
('1feb20ad-1ad1-4510-8d0d-1dc1c849af67','貧居詠懷贈樂天','劉禹錫','唐','唐诗','tang','','[]','若有金揮勝二疏。',30,'全唐诗/poet.tang.53000.json','["若有金揮勝二疏。", "（同前卷三五《酬夢得貧居詠懷見贈》自注引）。"]'),
('35eeae24-e915-4227-81d7-313dea5a09f4','酬樂天','劉禹錫','唐','唐诗','tang','','[]','鍊盡美少年。',41,'全唐诗/poet.tang.53000.json','["鍊盡美少年。", "（同前《夢得前所酬篇有鍊盡美少年之句因思往事兼詠今懷重以長句答之》）。"]'),
('58940ba3-35fb-45f6-99d8-27929ca34dd9','賀樂天談氏外孫女初生','劉禹錫','唐','唐诗','tang','','[]','從此引鴛雛。',206,'全唐诗/poet.tang.53000.json','["從此引鴛雛。", "（同前《談氏外孫生三日喜是男偶吟成篇兼戲呈夢得》自注引。", "以上四題皆承陶敏先生見示）（按：陶敏先生告：《南京日報》一九七八年十月二十八日刊許總《友誼的遺珍》一文，云劉禹錫作《贈日本僧智藏》詩，智藏有和詩云：「杯浮碧海海浮天，飄向中華五岳巔。", "佛法精微期妙悟，詩靈肸蠁總勾牽。", "流連勝境忘來處，契翕嘉賓結異緣。", "誰說个中多障礙，試開心鏡照飛烟。", "」云出「埋沒數百年的未刊鈔本」。", "此詩出處不明，姑附此以俟考詳。", "）。"]'),
('f694f435-8e02-494b-8c6a-886f83cbd61a','','路單','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('ad8f4608-c369-42b0-98e4-020f1fb1f6c0','和元常侍晦除浙東留題越亭（題擬）','路單','唐','唐诗','tang','','[]','謝安致理逾三載，黃霸清聲徹九重。',105,'全唐诗/poet.tang.53000.json','["謝安致理逾三載，黃霸清聲徹九重。", "猶輟珮環歸鳳闕，且將仁政到稽峰。", "林間立馬羅千騎，池上開筵醉一鐘。", "共喜甘棠有新詠，獨慚霜鬢又攀龍。", "（《桂林風土記》）（按：《全唐詩》卷五四七收此詩，作者誤爲路貫，今改正重錄之。", "）。"]'),
('79b5cfa0-06b7-46cd-865b-c5539d0185d0','樂天偶眠詩','盧貞','唐','唐诗','tang','','[]','放盃書桉上，枕臂火爐前。',24,'全唐诗/poet.tang.53000.json','["放盃書桉上，枕臂火爐前。", "（《吟窗雜錄》卷二六）。"]'),
('84045ce1-c890-4e04-a557-71ad4ffafc85','詠山魈','施肩吾','唐','唐诗','tang','','[]','山魈本是伍家奴，何事今爲聖者呼？小鬼不須乖去就，國家才子號肩吾。',109,'全唐诗/poet.tang.53000.json','["山魈本是伍家奴，何事今爲聖者呼？小鬼不須乖去就，國家才子號肩吾。", "（見何光遠《鑑誡錄》卷八）（《鑑戒錄》云：肩吾「及第後，遊南楚。", "楚多山魈爲患，俗號聖者。", "是時亦來館谷，攪擾施君，施君當風一詠，於是屏跡。", "詩曰〖略〗」。", "）。"]'),
('5f2d881a-c5e4-439c-8c56-deeedb9cccf0','下元歌','施肩吾','唐','唐诗','tang','','[]','契真之道飄颻易，動不動中如有寄。',55,'全唐诗/poet.tang.53000.json','["契真之道飄颻易，動不動中如有寄。", "那知有無可超忽，去住玄機此其義。", "（《雲笈七籤》卷八八施肩吾《養生辨疑訣》附）。"]'),
('009ffcda-056b-47e3-941c-c3f4908e3b3e','贈袁將軍','施肩吾','唐','唐诗','tang','','[]','白錦滿胸鷹未老，青鱗動匣劍長寒。',35,'全唐诗/poet.tang.53000.json','["白錦滿胸鷹未老，青鱗動匣劍長寒。", "（《千載佳句》卷上《人事部·將軍》）。"]'),
('a6ff31cd-a891-4f09-bb7e-e42c01d5f367','太白經附頌','施肩吾','唐','唐诗','tang','','[]','神水華池便是丹，東西高下自相看。',111,'全唐诗/poet.tang.53000.json','["神水華池便是丹，東西高下自相看。", "勸君莫把凡鉛弄，活計生涯便好捐。", "鉛則何妨本自鉛，鉛中何處覓神仙？", "東西南北還丹了，爭奈仙家不肯傳。", "同色同名合好音，亦能爍爍亦沉沉。", "乾坤顛倒驅雷雨，龍躍安能出上陰？", "（《正統道藏》本《太白經》）。"]'),
('578e8f1b-8f02-4069-8128-65af116823bb','皇恩寺（題擬）','潘咸','唐','唐诗','tang','','[]','睿（別本作「廣」）澤潭來數百年，海山高處有祇園。',155,'全唐诗/poet.tang.53000.json','["睿（別本作「廣」）澤潭來數百年，海山高處有祇園。", "禪林自是三三（別本作「山」）界，塵世誰知十二門。", "詩客迢迢尋義路，禪翁特特（別本作「轉」）起談軒。", "香爐頂上垂東注，萬派分明出一源。", "（見影印文淵閣《四庫全書》本《淳熙三山志》卷三五，所注別本指上海圖書館藏清紅格抄本。", "原署作者爲「潘誠」，今從《全唐詩》以咸爲正名。", "）。"]'),
('2c176405-66ab-4b86-8ae1-b99f56a3cd7e','歌','宜春頭陀','唐','唐诗','tang','','[]','經世學，經世學成無用著。',107,'全唐诗/poet.tang.53000.json','["經世學，經世學成無用著。", "山中樂，山中樂土堪耕鑿。", "癭飄有酒同君酌，醉臥草廬誰喚覺。", "松陰忽聽雙鳴（《中國醫籍考》卷七十引作「鳩」）鶴，起來日出穿林薄。", "（見《道藏·太平部》收《急救仙方》卷六十《仙授理傷續斷仙方序》引）。"]'),
('14ea00d8-ada7-4501-ab02-8187f89e46f1','樂道歌（《燈錄》作「獲珠吟」）','道常','唐','唐诗','tang','','[]','三界兮和燄（一作「幻」），六道兮如幻（一作「夢」），聖賢出世兮同（一作「如」）。',348,'全唐诗/poet.tang.53000.json','["三界兮和燄（一作「幻」），六道兮如幻（一作「夢」），聖賢出世兮同（一作「如」）。", "國土猶如水上泡，無常生滅頻（一作「無生滅」）遷變。", "唯有摩訶大般若（一作「般若堅」），堅（一作「猶」）如金剛是可羨（一作「不可讚」）。", "軟似兜羅大等空，極小纖（一作「小極微」）塵不可見。", "擁之令聚而不聚，撥之令散而不散，側耳欲聞而不聞，瞪目觀之不能見（一作「而不見」）。", "謌復謌，盤陀石上笑訶訶。", "笑復笑，青蘿松（一作「松影」）下高聲叫。", "自從頓獲此明珠（一作「獲得此心珠」），帝釋輪王都（一作「俱」）不要。", "不是山僧獨施爲，自古先賢作此調。", "不坐禪，不修道，任運逍遙只摩好（一作「麽了」）。", "但知萬（一作「能方」）法不干懷，無如（一作「始」）何曾有生老。", "（見《祖堂集》卷十七，注「一作」者，爲《景德傳燈錄》卷三十所收此詩之異文。", "）。"]'),
('e424b813-76fd-42b8-8a3c-3df6b904fd74','船子和尚東遊泊釣船處','愚公谷人','唐','唐诗','tang','','[]','和尚東來泊釣船，一溪秋水月明天。',100,'全唐诗/poet.tang.53000.json','["和尚東來泊釣船，一溪秋水月明天。", "此中定有高人出，爲憶前身幾百年。", "（《續機緣集》卷上）（按：清嘉慶六年三月二十七日，法忍寺天空閣毀於火，於灰燼中得小碣，中刻此詩，後勒會昌元年十一月款，書愚公谷人記。", "）。"]'),
('20e1da2c-08c8-4945-9dc4-d1295b8e4b03','逢友人','賈島','唐','唐诗','tang','','[]','還似不才命未通，相逢雲水思無窮。',88,'全唐诗/poet.tang.53000.json','["還似不才命未通，相逢雲水思無窮。", "清時年少爲幽客，寒月更深聽過鴻。", "東越山多連楚疊，南朝城古枕江空。", "蒼崖欲隱誰招我？姜子生涯只此中。", "（見《吟窗雜錄》卷十三梅堯臣《續金針詩格》引）。"]'),
('c6640f70-0934-4378-9f2f-958feb160991','送人','賈島','唐','唐诗','tang','','[]','半夜長安雨，燈前越客心。',29,'全唐诗/poet.tang.53000.json','["半夜長安雨，燈前越客心。", "（見同書卷十二沙門文彧《詩格》）。"]'),
('5f2c4007-e20d-4361-b2bd-99d6b503106a','桃氏林亭','賈島','唐','唐诗','tang','','[]','窗含明月樹，沙起白雲鷗。',31,'全唐诗/poet.tang.53000.json','["窗含明月樹，沙起白雲鷗。", "（見同書卷十四正字王元《詩中旨格》）。"]'),
('0338d586-a194-4c28-87b0-89d8eab76841','南臺對月','賈島','唐','唐诗','tang','','[]','僧歸湖裏寺，魚聽水邊經。',12,'全唐诗/poet.tang.53000.json','["僧歸湖裏寺，魚聽水邊經。"]'),
('da570122-9eed-4b2c-bc5e-132e09adae05','寄[貞]（正）空二上人','賈島','唐','唐诗','tang','','[]','老窺明鏡少，秋憶故山多。',28,'全唐诗/poet.tang.53000.json','["老窺明鏡少，秋憶故山多。", "（均見同書卷三五《賈島句對》）。"]'),
('125192f7-099a-4cfc-b6e8-01229b19145f','句 一','賈島','唐','唐诗','tang','','[]','風雷一夜雨，山川半年行。',34,'全唐诗/poet.tang.53000.json','["風雷一夜雨，山川半年行。", "（見同書卷十三王夢簡《進士王氏詩要格律》）。"]'),
('97a927d9-c474-4bd7-a236-19e20808d2a3','句 二','賈島','唐','唐诗','tang','','[]','祭閒收朔雪，弔後折寒花。',12,'全唐诗/poet.tang.53000.json','["祭閒收朔雪，弔後折寒花。"]'),
('c70d5da8-19dc-4879-a59a-9e2af6853cbb','句 三','賈島','唐','唐诗','tang','','[]','離人隔楚水，落葉滿長安。',31,'全唐诗/poet.tang.53000.json','["離人隔楚水，落葉滿長安。", "（均見同書卷十三僧虛中《流類手鑑》）。"]'),
('5202e617-2755-4bb8-bac4-a06f113b082d','梧桐詩','周賀','唐','唐诗','tang','','[]','只期丹鳳宿，不許別禽棲。',35,'全唐诗/poet.tang.53000.json','["只期丹鳳宿，不許別禽棲。", "（見《吟窗雜錄》卷十四正字王元《詩中旨格》）。"]'),
('64ac16be-36cc-4433-87d6-0c6bc59e23e0','句','周賀','唐','唐诗','tang','','[]','兩鬢已垂白，五湖歸釣魚。',25,'全唐诗/poet.tang.53000.json','["兩鬢已垂白，五湖歸釣魚。", "（見《唐詩紀事》卷七六）。"]'),
('09322169-1fa5-4f61-aa1e-57ca187da535','秋望','劉得仁','唐','唐诗','tang','','[]','西風蟬滿樹，東岸有殘暉。',31,'全唐诗/poet.tang.53000.json','["西風蟬滿樹，東岸有殘暉。", "（《吟窗雜錄》卷十徐衍《風騷要式》）。"]'),
('3fab094d-3004-4252-8188-f6445b718349','','賀蘭朋吉','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('83192071-aeae-4c24-b20e-f32b2fe57b64','句','賀蘭朋吉','唐','唐诗','tang','','[]','五更愁處雨，三月盡時花。',25,'全唐诗/poet.tang.53000.json','["五更愁處雨，三月盡時花。", "（見《吟窗雜錄》卷三五）。"]'),
('0379de5f-11f2-42e1-9183-d986938a4d1b','句','滕邁','唐','唐诗','tang','','[]','多少千條拂地垂。',31,'全唐诗/poet.tang.53000.json','["多少千條拂地垂。", "（《江湖小集》卷七紹嵩《江浙紀行集句詩》引）。"]'),
('3c533d33-5a3e-4c4b-977c-861b1f394946','玉泉寺次韻寄白樂天刺史','僧初','唐','唐诗','tang','','[]','古泉猶玉色，散木自閑身。',61,'全唐诗/poet.tang.53000.json','["古泉猶玉色，散木自閑身。", "挹秀尋芳躅，賡題步後塵。", "登山謝雙屐，漉酒一陶巾。", "誰得向清淨，居亭作主人。", "（見《古今禪藻集》卷四）。"]'),
('2f8f4399-7304-409a-8ac9-f445ecbe785b','悼故妓','李播','唐','唐诗','tang','','[]','直應人世無風月，始是心中忘却時。',79,'全唐诗/poet.tang.53000.json','["直應人世無風月，始是心中忘却時。", "（見《白氏長慶集》卷三五《對酒有懷寄李十九郎中》自注引）（按：李十九即李播，從郁賢皓先生《唐刺史考》卷一三一《蘄州》考證。", "）。"]'),
('01a7b736-d1e5-4761-966e-24dd6b0640b1','長相思','吳二娘','唐','唐诗','tang','','[]','深畫眉，淺畫眉，蟬鬢鬅鬙雲滿衣，陽臺行雨迴。',484,'全唐诗/poet.tang.53000.json','["深畫眉，淺畫眉，蟬鬢鬅鬙雲滿衣，陽臺行雨迴。", "巫山高，巫山低，暮雨瀟瀟郎不歸，空房獨守時。", "（見宋黃昇《唐宋諸賢絕妙詞選》卷一，原署爲白居易作）（〖1〗明刻本《吟窗雜錄》卷五十錄吳二娘《長相思令》云：「深黛眉，淺黛眉，十指蘢葱雲染衣，巫山行雨行〖疑爲迴之誤〗。", "巫山高，巫山低，暮暮朝朝良不歸，空房獨守誰？", "」〖2〗明楊慎《升菴詩話》卷四云：「吳二娘，杭州名妓也。", "有《長相思》一詞云：『深花枝，淺花枝，深淺花枝相間時，花枝難似伊。", "巫山高，巫山低，暮雨瀟瀟郎不歸，空房獨守時。", "』白樂天詩：『吳娘暮雨瀟瀟曲，自別江南久不聞。", "』又：『夜舞吳娘袖，春歌蠻子詞。", "』自注：『吳二娘歌詞有暮雨瀟瀟郎不歸之句。", "』《絕妙詞選》以此爲白樂天詞，誤矣。", "吳二娘亦杜公之黃四娘也，聊表出之。", "」今按：楊慎引白氏二詩，前詩爲《寄殷協律》，後詩爲《聽彈湘妃怨》。", "其訂黃氏之失，甚是。", "《吟窗雜錄》爲北宋末蔡傳所作書〖詳拙文《殷璠〈丹陽集〉輯考》〗，已徑題吳二娘作，可證。", "惟三本文字差異較大，黃昇所錄，似與白氏所聞者最爲接近，故錄爲正文，而以餘二本附於後。", "《全唐詩》卷八九○據黃昇所錄收歸白居易，今爲移正之。", "）。"]'),
('8b7cb149-77ed-42cd-bbbd-0f63572f9c81','','白居易','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('d0069dbf-0726-4440-8fc3-19dd1f95cc42','濟源上枉舒員外兩篇因酬六韻','白居易','唐','唐诗','tang','','[]','歇手不判案，舉頭仍見山。',98,'全唐诗/poet.tang.53000.json','["歇手不判案，舉頭仍見山。", "雖來鞍馬上，不離詩酒間。", "濟源三臨泛，王屋一登攀。", "猶嫌百里近，祇得十日閒。", "明朝却歸府，塵事如循環。", "猶聽瑤華曲，稍開風土顏。", "（見《四部叢刊》影印那波道圓本《白氏文集》卷五二）。"]'),
('1d48d728-057e-425e-85af-754a45addbe0','同崔十八宿龍門兼寄令狐尚書馮常侍','白居易','唐','唐诗','tang','','[]','水碧玉磷磷，龍門秋勝春。',57,'全唐诗/poet.tang.53000.json','["水碧玉磷磷，龍門秋勝春。", "山中一夜月，海內兩閒人。", "等是幽棲伴，俱非富貴身。", "尚書與常侍，不可得相親。", "（見前書卷五七）。"]'),
('210bb1e1-f67f-4659-b105-31e6fc6893d3','雨歇池上','白居易','唐','唐诗','tang','','[]','簷前微雨歇，池上凉風起。',105,'全唐诗/poet.tang.53000.json','["簷前微雨歇，池上凉風起。", "橋竹碧鮮鮮，岸移莎靡靡。", "蒼然古苔石，清淺平流水。", "何言中門前，便是深山裏。", "雙僮侍坐臥。", "一杖扶行止。", "飢聞麻粥香，渴覺雲湯美。", "平生所好物，今日多在此。", "此外更何思？", "市朝心已矣！（見前書卷六三）。"]'),
('5ddc407e-feb6-4815-9eeb-71b9729f4b91','十二時行孝文 一','白居易','唐','唐诗','tang','','[]','平旦寅，早起堂前參二親。',33,'全唐诗/poet.tang.53000.json','["平旦寅，早起堂前參二親。", "處分家中送疎水，莫[教]（交）父母喚頻聲。"]'),
('adef0210-ea0a-4877-b18c-7c76e3f20a03','十二時行孝文 二','白居易','唐','唐诗','tang','','[]','日出卯，立身之本須行孝。',33,'全唐诗/poet.tang.53000.json','["日出卯，立身之本須行孝。", "甘{餄右爲危}盤中莫使空，時時奉上知饑飽。"]'),
('b835f60f-4d4d-4c10-b467-fc9bbf213d82','十二時行孝文 三','白居易','唐','唐诗','tang','','[]','食時辰，居家治務最須懃。',28,'全唐诗/poet.tang.53000.json','["食時辰，居家治務最須懃。", "無事等閑莫外宿，歸來勞費父嫌憎。"]'),
('a0ac99f8-35ce-4c3a-a4fe-7c194afac9e3','十二時行孝文 四','白居易','唐','唐诗','tang','','[]','隅中巳，終孝之心不合二。',29,'全唐诗/poet.tang.53000.json','["隅中巳，終孝之心不合二。", "竭力懃酬乳哺恩，自得名高上史記。", "。"]'),
('3353d090-1eba-4b6f-a4af-c66192a4b963','十二時行孝文 五','白居易','唐','唐诗','tang','','[]','正南午，侍奉尊親莫辭[訴]（訢）。',41,'全唐诗/poet.tang.53000.json','["正南午，侍奉尊親莫辭[訴]（訢）。", "迴乾就濕長成人，如今去（疑爲「未」字）合論辛苦。"]'),
('21357813-0982-40a2-a2e6-a4790cfc1dd8','十二時行孝文 六','白居易','唐','唐诗','tang','','[]','日昳未，在家行孝兼行義。',33,'全唐诗/poet.tang.53000.json','["日昳未，在家行孝兼行義。", "莫取妻言兄弟疏，却[教]（交）父母流雙淚。"]'),
('8634fa4b-9676-46d2-a166-a46011d1a7db','十二時行孝文 七','白居易','唐','唐诗','tang','','[]','晡時申，父母堂前莫動塵。',28,'全唐诗/poet.tang.53000.json','["晡時申，父母堂前莫動塵。", "縱月些些不稱意，向前小語善諮聞。"]'),
('c7816d93-9d4f-4c14-8757-fd0fb53a10d4','十二時行孝文 八','白居易','唐','唐诗','tang','','[]','日入酉，但願父母得長[壽]（受）。',33,'全唐诗/poet.tang.53000.json','["日入酉，但願父母得長[壽]（受）。", "身如松栢色堅政，莫學愚人多飲酒。"]'),
('2ccf359f-f8f0-4edf-a1fc-c245776601ba','十二時行孝文 九','白居易','唐','唐诗','tang','','[]','黃昏戌，下簾拂牀早交畢。',28,'全唐诗/poet.tang.53000.json','["黃昏戌，下簾拂牀早交畢。", "安置父母臥高堂，睡定然乃抽身出。"]'),
('412f7ac1-d348-4a18-b686-1f004c564d71','十二時行孝文 十','白居易','唐','唐诗','tang','','[]','人定亥，父母年高須[保]（報）愛。',33,'全唐诗/poet.tang.53000.json','["人定亥，父母年高須[保]（報）愛。", "但能行孝向尊親，總得揚名於後世。"]'),
('4af82098-a3dd-4302-a62b-c506ed502e1d','十二時行孝文 十一','白居易','唐','唐诗','tang','','[]','夜半子，孝養父母存終始。',28,'全唐诗/poet.tang.53000.json','["夜半子，孝養父母存終始。", "百年恩愛暫時間，莫學愚人不歡喜。"]'),
('aa6055df-6f79-4497-9efa-a410f1158bc0','十二時行孝文 十二','白居易','唐','唐诗','tang','','[]','鷄鳴丑，高樓大宅得安久。',56,'全唐诗/poet.tang.53000.json','["鷄鳴丑，高樓大宅得安久。", "常勸父母發慈心，孝得題名終不朽。", "（見伯三八二一卷。", "原題作「白侍郎作《十二時行孝文》」）。"]'),
('ffa3b5fe-ae50-45d9-90d6-cdfff9a52225','行香子（清涼山文殊讚）','白居易','唐','唐诗','tang','','[]','文殊菩薩，出化清涼，神通力以（一作「應」）現他方。',153,'全唐诗/poet.tang.53000.json','["文殊菩薩，出化清涼，神通力以（一作「應」）現他方。", "真（一作「身」）座金毛師子，微放珠光。", "衆生仰持寶蓋，絕名香。", "我今發願，虔誠歸命，不求富貴，不戀榮華。", "願當來世，生（一作無「世」、「生」二字，下同）淨土，法王家。", "願當來世，生淨土，法王家。", "（見日本長惠編《魚山詩鈔》，注「一作」者，爲《聲明古調》本之異文。", "）。"]'),
('c319582f-9bb1-479a-a0e4-772b5ea8eb1e','鳥窠和尚贊','白居易','唐','唐诗','tang','','[]','形羸骨瘦久修行，一納麻衣稱道情。',43,'全唐诗/poet.tang.53000.json','["形羸骨瘦久修行，一納麻衣稱道情。", "曾結草庵倚碧樹，天涯知有鳥窠名。", "（見《祖堂集》卷三）。"]'),
('cdf4d99f-fc45-45df-8595-3d7798719749','贈鳥窠和尚詩（題擬）','白居易','唐','唐诗','tang','','[]','空門有路不知處，頭白齒黃猶念經。',81,'全唐诗/poet.tang.53000.json','["空門有路不知處，頭白齒黃猶念經。", "何年飲著聲聞酒，迄至如今醉未醒。", "（同前）（按：《全唐詩》卷四五八《戲禮經老僧》與此詩後二句同，前二句全異，未審爲一詩抑爲二詩。", "）。"]'),
('65bdbaab-4ac0-43ee-983f-ec89a93a6ee9','南嶽橫龍寺（題擬）','白居易','唐','唐诗','tang','','["\u8861\u5c71"]','月射冷光新殿宇，風敲清韻古杉松。',45,'全唐诗/poet.tang.53000.json','["月射冷光新殿宇，風敲清韻古杉松。", "問師寶額因何立，笑指橫溪有臥龍。", "（見《南嶽總勝集》卷中）。"]'),
('0834a91c-23f8-4085-af70-95613f4dfb46','遊紫霄宮七言八句（藏頭拆字詩）','白居易','唐','唐诗','tang','','[]','水洗塵埃道味甞，甘於於名利相相忘。',168,'全唐诗/poet.tang.53000.json','["水洗塵埃道味甞，甘於於名利相相忘。", "心懷天洞丹霞客，各誦三清紫府章。", "早裏採蓮歌達旦，一輪明月桂飄香。", "日高公子還相覓，見得山中好酒漿。", "（見宋桑世昌《回文類聚》卷二引）（按：《回文類聚》收此詩作環行排列，各句首字皆略去。", "附《讀法》云：「每句取第一字下半爲起字，從右轉，首句用漿字之下半水字讀起，如『水洗塵埃道味甞，甘於名利兩相忘』是也。", "」）。"]'),
('fe624da0-0812-4a55-a568-241a6563cc42','讚崔氏夫人（幷序○題擬） 一','白居易','唐','唐诗','tang','','[]','亭亭獨步□枝花，紅臉青娥不是誇。',32,'全唐诗/poet.tang.53000.json','["亭亭獨步□枝花，紅臉青娥不是誇。", "作將喜貌爲愁貌，未慣離家往婿家。"]'),
('896ed6be-1ef0-462c-aee0-8409aa87a0c6','讚崔氏夫人（幷序○題擬） 二','白居易','唐','唐诗','tang','','[]','拜別高堂日欲斜，紅巾拭淚貴新花。',76,'全唐诗/poet.tang.53000.json','["拜別高堂日欲斜，紅巾拭淚貴新花。", "徒來生處却爲客，今日隨夫始是家。", "（見《敦煌掇瑣》二○錄伯二六三三卷。", "原附《崔氏夫人要女文一本》後，題作「白侍郎讚」。", "）。"]'),
('b1adce9a-1ddd-416e-8c95-bc893dc94c73','采石墓','白居易','唐','唐诗','tang','','[]','采石江邊李白墳，遶田無限草連雲。',121,'全唐诗/poet.tang.53000.json','["采石江邊李白墳，遶田無限草連雲。", "可憐荒壠泉骨，曾有驚天動地文。", "但是詩人多薄命，就中淪落不過君。", "渚蘋溪草猶堪薦，大雅遺風不可聞。", "（見《采石志》，轉錄自《李白在安徽》）（按：《全唐詩》卷四四○收本詩，缺末二句，今重錄。", "今人或謂末二句係人僞託。", "）。"]'),
('84db7383-dbe0-4951-bd30-57c9cbc0a631','宿雲門寺','白居易','唐','唐诗','tang','','[]','昨夜有風雨，雲奔天地合。',49,'全唐诗/poet.tang.53000.json','["昨夜有風雨，雲奔天地合。", "龍吟古石樓，虎嘯層巖閣。", "幽意未盡懷，更行三五匝。", "（《會稽掇英總集》卷七）。"]'),
('195544c5-56fc-4628-9570-5f749fb1f68d','會二同年','白居易','唐','唐诗','tang','','[]','一樽聊接故人歡，百歲堪嗟鬢漸殘。',40,'全唐诗/poet.tang.53000.json','["一樽聊接故人歡，百歲堪嗟鬢漸殘。", "莫見白雲容易愛，照湖澄碧四明寒。", "（同前卷十三）。"]'),
('c60795c4-636f-413a-a5bd-c48d1f5cd1e5','題法華山天衣寺','白居易','唐','唐诗','tang','','[]','山爲蓮宮作畫屏，樓臺迤邐插青冥。',88,'全唐诗/poet.tang.53000.json','["山爲蓮宮作畫屏，樓臺迤邐插青冥。", "雲生座底鋪金地，風起松梢韻寶鈴。", "龍噴水聲連擊罄，猿啼月色閑持經。", "時人不信非凡境，試入玄關一夜聽。", "（同前卷八。", "以上三首參鄒志方《唐詩補錄》收入）。"]'),
('31dec283-f5f2-4267-8ada-1cd63e6c6277','戲酬皇甫十再勸酒','白居易','唐','唐诗','tang','','[]','淨名居士眼方丈，玄晏先生釀老春。',76,'全唐诗/poet.tang.53000.json','["淨名居士眼方丈，玄晏先生釀老春。", "手把屈巵未（疑應作「來」）勸我，世間何處覓波旬？", "（前二句見《千載佳句》卷上《人事部·閑放》後二句見卷下《宴喜部·酒》）。"]'),
('9f90026d-dc63-43ca-873b-cd3943ca07df','重陽日（一無「日」字）','白居易','唐','唐诗','tang','','[]','敬亭山外人歸遠，峽石溪邊水去斜。',68,'全唐诗/poet.tang.53000.json','["敬亭山外人歸遠，峽石溪邊水去斜。", "茅屋老妻良釀酒，東籬黃菊任開花。", "（前二句見《千載佳句》卷下《別離部·送別》，後二句見《草木部·菊酒》）。"]'),
('6d914ec1-9b1f-4269-ad42-0497d22ac1ff','新艷','白居易','唐','唐诗','tang','','[]','雲環獨𢮿細蜻蜓，雪手輕柔玳瑁箏。',44,'全唐诗/poet.tang.53000.json','["雲環獨𢮿細蜻蜓，雪手輕柔玳瑁箏。", "飛鴈一行挑玉柱，十三絃上語嚶嚶。", "（同上《宴喜部·箏》）。"]'),
('0d59da35-b5fc-4559-9c8d-1ad633e69457','江郎山','白居易','唐','唐诗','tang','','[]','林慮雙童長不食，江郎三子夢還家。',74,'全唐诗/poet.tang.53000.json','["林慮雙童長不食，江郎三子夢還家。", "安得此身生羽翼，與君來往共烟霞。", "（《古今圖書集成·職方典》卷一○一六《衢州府部》、《山川典》卷一三○《江郎山部》）。"]'),
('95594407-1603-4581-a2e7-f0231d513152','題天柱峰','白居易','唐','唐诗','tang','','[]','太微星斗拱瓊宮，聖祖琳宮鎮九垓。',104,'全唐诗/poet.tang.53000.json','["太微星斗拱瓊宮，聖祖琳宮鎮九垓。", "天柱一峰擎日月，洞門千仞鎖雲雷。", "玉光白橘相爭秀，金翠佳蓮蕊鬬開。", "時訪左慈高隱處，紫清仙鶴認巢來。", "（《天柱山志》）（按：《輿地紀勝》收三、四兩句爲南唐李明作，詳本書卷四十四。", "）。"]'),
('cd6d21b0-6808-4f22-a9fd-3af178e6f3c7','讚碎金','白居易','唐','唐诗','tang','','[]','獡頭𧭉趠人難識，瀎𣳡𥏠{矲右爲面}惱家心。',51,'全唐诗/poet.tang.53000.json','["獡頭𧭉趠人難識，瀎𣳡𥏠{矲右爲面}惱家心。", "寫向篋中甚敬重，要來一字一{碈右上爲尤}（當即「碎」字）金。"]'),
('0661a98d-777c-4802-bc70-92031a5fda5a','寄盧協律','白居易','唐','唐诗','tang','','[]','滿卷玲瓏實碎金，展開無不稱人心。',56,'全唐诗/poet.tang.53000.json','["滿卷玲瓏實碎金，展開無不稱人心。", "曉眉歌得白居易，藐䓬盧郎更敢尋。", "（二首見敦煌遺書斯六二○四卷，皆署「白侍郎」）。"]'),
('9bedaf9e-8f45-4e4e-896b-5e4479d0c5ba','登西山望硤石湖','白居易','唐','唐诗','tang','','[]','菱歌清唱棹舟迴，樹裏南湖似鑒開。',103,'全唐诗/poet.tang.53000.json','["菱歌清唱棹舟迴，樹裏南湖似鑒開。", "平障煙浮低落日，出溪路細長新苔。", "居民地僻常無事，太守官閑好獨來。", "猶憶長安論詩句，至今惆悵獨書臺。", "（見《海昌勝蹟志》卷三。", "同書引秦瀛語，謂疑出後人附會。", "此詩承陶敏先生錄示。", "）。"]'),
('3f6ea742-acc5-42d4-9bd2-f19d9cda529f','和楊同州寒食乾坑會後聞楊工部欲到知予與工部有敷水之期榮喜雖多歡宴且阻辱示長句因而答之','白居易','唐','唐诗','tang','','[]','往來東道千餘騎，新舊西曹兩侍郎。',148,'全唐诗/poet.tang.53000.json','["往來東道千餘騎，新舊西曹兩侍郎。", "（去年兄自工部拜同州，今年弟從常州拜工部。", "）家占冬官傳印綬，路逢春日助恩光。", "停留五馬經寒食，指點三峰過故鄉。", "猶恨乾坑敷水會，差池歸雁不成行。", "（見金澤文庫本《白氏文集》卷六五，據朱金城先生《白居易年譜》大和九年譜轉引。", "《千載佳句》卷下《宴喜部·宴後》引五、六兩句）。"]'),
('d2e07d59-e313-4b0b-bb89-d9e456d1ea53','早春閑行','白居易','唐','唐诗','tang','','[]','鸎早乍啼猶冷落，花寒欲發尚遲疑。',42,'全唐诗/poet.tang.53000.json','["鸎早乍啼猶冷落，花寒欲發尚遲疑。", "（見日本大江維時《千載佳句》卷上《四時部·早春》）。"]'),
